module fsm(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);

reg [4:0] state;

localparam IDLE = 5'b00001,
          STATE1 = 5'b00010,
          STATE2 = 5'b00100,
          STATE3 = 5'b01000,
          STATE4 = 5'b10000;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        state <= IDLE;
        MATCH <= 1'b0;
    end
    else begin
        case (state)
            IDLE: begin
                if (IN) begin
                    state <= STATE1;
                    MATCH <= 1'b0;
                end
                else begin
                    state <= IDLE;
                    MATCH <= 1'b0;
                end
            end
            STATE1: begin
                if (IN) begin
                    state <= STATE1;
                    MATCH <= 1'b0;
                end
                else begin
                    state <= STATE2;
                    MATCH <= 1'b0;
                end
            end
            STATE2: begin
                if (IN) begin
                    state <= STATE3;
                    MATCH <= 1'b0;
                end
                else begin
                    state <= IDLE;
                    MATCH <= 1'b0;
                end
            end
            STATE3: begin
                if (IN) begin
                    state <= STATE4;
                    MATCH <= 1'b0;
                end
                else begin
                    state <= STATE2;
                    MATCH <= 1'b0;
                end
            end
            STATE4: begin
                if (IN) begin
                    state <= STATE1;
                    MATCH <= 1'b0;
                end
                else begin
                    state <= STATE2;
                    MATCH <= 1'b1;
                end
            end
            default: begin
                state <= IDLE;
                MATCH <= 1'b0;
            end
        endcase
    end
end

endmodule
